     1→"use client";
     2→
     3→import { useCallback, useEffect, useRef, useState } from "react";
     4→import { socket } from "@/lib/socket";
     5→
     6→type MessageRole = "user" | "mira" | "system";
     7→
     8→interface ChatMessage {
     9→  id: string;
    10→  role: MessageRole;
    11→  text: string;
    12→}
    13→
    14→interface ProductItem {
    15→  title: string;
    16→  price: string;
    17→  source: string;
    18→  image_url: string;
    19→  link: string;
    20→  rating?: number;
    21→  rating_count?: number;
    22→}
    23→
    24→interface ProductCard {
    25→  id: string;
    26→  query: string;
    27→  items: ProductItem[];
    28→}
    29→
    30→const DEMO_USER_ID = "00000000-0000-4000-a000-000000000001";
    31→
    32→export default function ChatPage() {
    33→  const [userId, setUserId] = useState(DEMO_USER_ID);
    34→  const [messages, setMessages] = useState<ChatMessage[]>([]);
    35→  const [products, setProducts] = useState<ProductCard[]>([]);
    36→  const [input, setInput] = useState("");
    37→  const [sessionActive, setSessionActive] = useState(false);
    38→  const [connected, setConnected] = useState(false);
    39→  const miraBufferRef = useRef("");
    40→  const messagesEndRef = useRef<HTMLDivElement>(null);
    41→
    42→  const scrollToBottom = useCallback(() => {
    43→    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    44→  }, []);
    45→
    46→  useEffect(() => {
    47→    scrollToBottom();
    48→  }, [messages, products, scrollToBottom]);
    49→
    50→  // Socket connection & listeners
    51→  useEffect(() => {
    52→    socket.connect();
    53→
    54→    socket.on("connect", () => setConnected(true));
    55→    socket.on("disconnect", () => setConnected(false));
    56→
    57→    socket.on("mira_speech", (data: { text: string; is_chunk: boolean }) => {
    58→      miraBufferRef.current += data.text;
    59→      const currentText = miraBufferRef.current;
    60→
    61→      setMessages((prev) => {
    62→        const last = prev[prev.length - 1];
    63→        if (last && last.role === "mira" && last.id.startsWith("mira-stream-")) {
    64→          return [
    65→            ...prev.slice(0, -1),
    66→            { ...last, text: currentText },
    67→          ];
    68→        }
    69→        return [
    70→          ...prev,
    71→          { id: `mira-stream-${Date.now()}`, role: "mira", text: currentText },
    72→        ];
    73→      });
    74→    });
    75→
    76→    socket.on("tool_result", (data: { type: string; query: string; items: ProductItem[] }) => {
