    66→
    67→      {step === "signin" && (
    68→        <GoogleSignIn onSuccess={handleSignIn} onError={setError} />
    69→      )}
    70→
    71→      {step === "profile" && user && (
    72→        <ProfileForm
    73→          user={user}
    74→          onComplete={handleProfileComplete}
    75→          onError={setError}
